create table public.automation_rules (id uuid primary key default gen_random_uuid(),organization_id uuid not null references public.organizations(id) on delete cascade,rule_type text not null check(rule_type in('recurring_contribution','overdue_reminder','loan_reminder','event_reminder','scheduled_report')),name text not null,enabled boolean not null default true,configuration jsonb not null default '{}',next_run_at timestamptz,last_run_at timestamptz,created_by uuid references auth.users(id),created_at timestamptz not null default now());
create table public.automation_runs (id uuid primary key default gen_random_uuid(),automation_rule_id uuid not null references public.automation_rules(id) on delete cascade,organization_id uuid not null references public.organizations(id) on delete cascade,status text not null check(status in('running','completed','failed','skipped')),result jsonb not null default '{}',started_at timestamptz not null default now(),finished_at timestamptz,error_message text);
create index automation_rules_org_next_idx on public.automation_rules(organization_id,enabled,next_run_at);create index automation_runs_rule_idx on public.automation_runs(automation_rule_id,started_at desc);
alter table public.automation_rules enable row level security;alter table public.automation_runs enable row level security;
create policy "managers read automation rules" on public.automation_rules for select using(public.can_manage_organization(organization_id));create policy "managers write automation rules" on public.automation_rules for all using(public.can_manage_organization(organization_id)) with check(public.can_manage_organization(organization_id));
create policy "managers read automation runs" on public.automation_runs for select using(public.can_manage_organization(organization_id));
